#include<bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=2e3+5;
int n,ans,a[maxn],dp[maxn][maxn];
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>a[i];
		dp[i][i]=a[i]*n;
	}
	for(int l=2;l<=n;l++){
		for(int i=1,j;(j=i+l-1)<=n;i++){
			dp[i][j]=max(dp[i+1][j]+a[i]*(n-l+1),dp[i][j-1]+a[j]*(n-l+1));
		}
	}
	cout<<dp[1][n];
	return 0;
}
